package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.io.StringWriter;

public class CSVFormatTest {

    @Test
    public void testPrint() throws IOException {
        // Create a StringWriter to use as Appendable
        StringWriter stringWriter = new StringWriter();

        // Create an instance of CSVFormat
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // Call the print method
        CSVPrinter csvPrinter = csvFormat.print(stringWriter);

        // Verify that CSVPrinter is not null
        assertNotNull(csvPrinter);

        // Verify the output in StringWriter
        assertEquals(System.lineSeparator(), stringWriter.toString());
    }
}
